10	import java.util.function.Function;
11	
12	public class StageExecutor {
13	
14	    private static final ObjectMapper mapper = new ObjectMapper();
15	
16	    public static ObjectNode execute(EntityDTO dto,
17	                                     Function<EntityDTO, ObjectNode> task) {
18	        try {
19	            return task.apply(dto);
20	        } catch (Exception ex) {
21	            // transaction roll back
22	            // Mark rollback-only ONLY if a tx is active
23	            try {
24	                if (TransactionSynchronizationManager.isActualTransactionActive()) {
25	                    TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();
26	                }
27	            } catch (Exception ignore) {}
28	
29	            // Catch all exceptions and return a standardized response structure
30	            ObjectNode err = mapper.createObjectNode();
31	            err.put("code", EntityProcessingCode.SYSTEM_ERROR);
32	            err.put("errMessage", ex.getMessage());
33	            return err;
34	        }
35	    }
36	}
